import{_ as n,o,c as e,a0 as a}from"./chunks/framework.CSK6mTG2.js";const c=JSON.parse('{"title":"Agent智能体：从\\"聊天\\"到\\"干活\\"","description":"","frontmatter":{"title":"Agent智能体：从\\"聊天\\"到\\"干活\\"","author":"唐超","date":"2026-07-16T00:00:00.000Z"},"headers":[],"relativePath":"menuAI/agent-intelligent-body.md","filePath":"menuAI/agent-intelligent-body.md"}'),l={name:"menuAI/agent-intelligent-body.md"};function s(g,t,i,r,u,p){return o(),e("div",null,[...t[0]||(t[0]=[a(`<h1 id="agent智能体-从-聊天-到-干活" tabindex="-1">Agent智能体：从&quot;聊天&quot;到&quot;干活&quot; <a class="header-anchor" href="#agent智能体-从-聊天-到-干活" aria-label="Permalink to &quot;Agent智能体：从&quot;聊天&quot;到&quot;干活&quot;&quot;">​</a></h1><p>你用大模型做过什么？大概率是&quot;聊天&quot;——你问，它答，像个聪明的百科全书。但你有没有想过：能不能让它真的<strong>干活</strong>？比如&quot;帮我查一下今天北京的天气，然后通知小李带伞&quot;，这事大模型自己干不了，它没有手。</p><p><strong>Agent（智能体）</strong> 就是来解决这个问题的。简单说，Agent = 大模型 + 工具 + 执行循环。它让大模型不只是&quot;说&quot;，而是&quot;做&quot;。</p><h2 id="从-嘴-到-手-agent的核心架构" tabindex="-1">从&quot;嘴&quot;到&quot;手&quot;：Agent的核心架构 <a class="header-anchor" href="#从-嘴-到-手-agent的核心架构" aria-label="Permalink to &quot;从&quot;嘴&quot;到&quot;手&quot;：Agent的核心架构&quot;">​</a></h2><p>想象一个刚入职的实习生。老板说：&quot;帮我把这个月的销售数据整理成表格，发给财务老张。&quot;</p><p>一个只会聊天的实习生会说什么？&quot;好的老板，不过我没有办法操作你的电脑，我只能说说我对销售数据的理解。&quot;</p><p>一个Agent实习生呢？它会这么思考：</p><ol><li><strong>理解任务</strong>：老板让我整理销售数据、发邮件</li><li><strong>规划步骤</strong>：先从ERP系统导出数据 → 整理成表格 → 写邮件 → 发送</li><li><strong>执行工具</strong>：调用&quot;导出Excel&quot;工具 → 调用&quot;发送邮件&quot;工具</li><li><strong>检查结果</strong>：邮件发送成功了吗？失败了怎么办？</li></ol><p>这个&quot;理解→规划→执行→检查&quot;的循环，就是Agent的基本工作流。<strong>大模型在其中的角色是&quot;大脑&quot;，负责思考和决策；工具是&quot;手和脚&quot;，负责实际执行。</strong></p><p>拆开来看，Agent通常包含这几个部分：</p><ul><li><strong>规划模块（Planning）</strong>：把一个模糊的大任务拆成具体的步骤</li><li><strong>记忆模块（Memory）</strong>：记住之前的操作和结果</li><li><strong>工具模块（Tools）</strong>：能调用什么外部能力（查数据库、发邮件、调API等）</li><li><strong>执行循环（Action Loop）</strong>：不断执行→检查→调整，直到任务完成</li></ul><h2 id="工具调用-agent的-手" tabindex="-1">工具调用：Agent的&quot;手&quot; <a class="header-anchor" href="#工具调用-agent的-手" aria-label="Permalink to &quot;工具调用：Agent的&quot;手&quot;&quot;">​</a></h2><p>Agent最核心的能力是调用工具。模型本身再强，也只是&quot;脑子里会&quot;，工具才能让它&quot;动手做&quot;。</p><p>目前主流的工具调用方式有三种：</p><h3 id="_1-function-calling-函数调用" tabindex="-1">1. Function Calling（函数调用） <a class="header-anchor" href="#_1-function-calling-函数调用" aria-label="Permalink to &quot;1. Function Calling（函数调用）&quot;">​</a></h3><p>这是最基础的方式。你可以给大模型描述一个函数：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>工具名：send_email</span></span>
<span class="line"><span>参数：to（收件人），subject（主题），body（正文）</span></span></code></pre></div><p>大模型根据你的指令，判断需要调用这个函数，然后生成参数。大模型的输出不再是纯文字，而是一个结构化的&quot;调用指令&quot;——告诉系统：&quot;我要调用send_email，收件人是laozhang@company.com，主题是销售数据……&quot;</p><p>你可以理解为：<strong>Function Calling是大模型和服务端的一个&quot;握手协议&quot;</strong>。大模型说&quot;我想干什么&quot;，服务端来实际执行。</p><h3 id="_2-mcp协议-model-context-protocol" tabindex="-1">2. MCP协议（Model Context Protocol） <a class="header-anchor" href="#_2-mcp协议-model-context-protocol" aria-label="Permalink to &quot;2. MCP协议（Model Context Protocol）&quot;">​</a></h3><p>Function Calling是一对一的关系——一个模型调用一个工具。如果我想让大模型同时调用五六个不同系统的工具呢？每个系统有自己的接口规范，你得一个一个对接。</p><p><strong>MCP就像一个&quot;万能转接头&quot;</strong>。Anthropic在2024年底开源了这个协议，它定义了一套标准，让任何大模型可以用同一套方式调用任何工具。</p><p>打个比方：Function Calling像是每种手机都有自己独特的充电线，而MCP是USB-C——一个接口，什么设备都能插。</p><p>MCP的核心优势在于：</p><ul><li><strong>标准化</strong>：工具描述、调用、返回都是统一格式</li><li><strong>可复用</strong>：写一次MCP工具，各种模型都能用</li><li><strong>安全隔离</strong>：工具运行在独立进程，不影响模型本身</li></ul><h3 id="_3-多agent协作" tabindex="-1">3. 多Agent协作 <a class="header-anchor" href="#_3-多agent协作" aria-label="Permalink to &quot;3. 多Agent协作&quot;">​</a></h3><p>单个Agent再强，也有能力上限。<strong>多Agent系统</strong>让多个Agent分工合作，各司其职。</p><p>比如上文那个&quot;整理销售数据并发邮件&quot;的任务，可以拆成：</p><ul><li><strong>数据Agent</strong>：专门负责从各种系统拉取数据</li><li><strong>分析Agent</strong>：负责数据清洗和统计</li><li><strong>通信Agent</strong>：负责写邮件、通知相关人</li></ul><p>三个Agent各管一摊，通过消息传递协作。这就像一个公司里有财务部、技术部、市场部，各部门做自己的事，最后合力完成大项目。</p><p>多Agent的协调方式也有讲究：</p><ul><li><strong>串行</strong>：一个Agent做完交给下一个，适合线性流程</li><li><strong>并行</strong>：多个Agent同时工作，最后汇总结果</li><li><strong>层级</strong>：一个&quot;主Agent&quot;负责任务分配，下面管着若干&quot;子Agent&quot;</li></ul><h2 id="react-让agent-边想边做" tabindex="-1">ReAct：让Agent&quot;边想边做&quot; <a class="header-anchor" href="#react-让agent-边想边做" aria-label="Permalink to &quot;ReAct：让Agent&quot;边想边做&quot;&quot;">​</a></h2><p>说一个Agent领域最重要的思考框架——<strong>ReAct</strong>（Reasoning + Acting）。</p><p>它的核心思想很朴素：<strong>不要闷头干，也不要光说不干，要边想边做。</strong></p><p>ReAct的工作循环是这样的：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>思考：我现在需要做什么？</span></span>
<span class="line"><span>行动：执行一个工具</span></span>
<span class="line"><span>观察：结果是什么？</span></span>
<span class="line"><span>思考：基于结果，下一步做什么？</span></span>
<span class="line"><span>……循环直到完成</span></span></code></pre></div><p>这个循环的好处是：每一步都有迹可循。如果任务中途出错，Agent可以回溯到某个&quot;思考&quot;节点，分析哪里出了问题。</p><p>你可以把ReAct理解为&quot;工作日志&quot;。Agent不是在黑箱里闷头执行，而是把每一步的思考都&quot;说出来&quot;，形成一条可追溯的行动链。</p><h2 id="为什么agent比普通聊天强大得多" tabindex="-1">为什么Agent比普通聊天强大得多 <a class="header-anchor" href="#为什么agent比普通聊天强大得多" aria-label="Permalink to &quot;为什么Agent比普通聊天强大得多&quot;">​</a></h2><p>回到最开始的问题：普通聊天和大模型Agent的区别是什么？</p><p>打个比方：普通聊天像是你和一只鹦鹉对话——它学舌很厉害，能模仿你说各种话，但它不会真的帮你办事。Agent则像是一个<strong>助理</strong>，你交代任务，它领了就去干，干完了给你汇报。</p><p>这个区别的本质在于：</p><ul><li><strong>普通聊天</strong>：大模型是&quot;终点&quot;——输入进去，输出出来，结束</li><li><strong>Agent</strong>：大模型是&quot;枢纽&quot;——接收任务，通过工具连接外部世界，形成闭环</li></ul><p>也因为如此，Agent天然适合复杂、多步骤、长链条的任务：</p><ul><li>自动化办公流程</li><li>数据分析报告生成</li><li>智能客服（能查订单、改状态、发通知）</li><li>代码审查 + 自动修复</li><li>科研文献检索 + 综述生成</li></ul><h2 id="前端开发者能怎么用agent" tabindex="-1">前端开发者能怎么用Agent <a class="header-anchor" href="#前端开发者能怎么用agent" aria-label="Permalink to &quot;前端开发者能怎么用Agent&quot;">​</a></h2><p>作为前端开发者，你完全可以基于Agent构建更智能的应用。比如：</p><p><strong>在网页里嵌入Agent能力</strong>：用户问一个问题，Agent自动帮你查数据库、调用内部API，组装成答案返回。</p><p><strong>构建AI助手类产品</strong>：不只是对话，而是让AI真正替你操作。比如&quot;帮我约一个周五下午3点和小明的会议&quot;，Agent自动查日程、发邀请。</p><p><strong>自动化工作流</strong>：重复性的前端任务（生成文档、生成测试用例），可以让Agent来替你完成。</p><p>Agent最激动人心的地方在于：它让大模型从&quot;展示智能&quot;走向&quot;使用智能&quot;——从知道答案，到真正改变世界。</p><hr><p><em>下篇预告：了解了Agent怎么工作，下一篇我们来聊聊&quot;让大模型真正用上工具&quot;的实战方法——Skill体系怎么设计，怎么写一个真正好用的工具。</em></p>`,54)])])}const d=n(l,[["render",s]]);export{c as __pageData,d as default};
